const articlesDatabaseRaw = [
    {"title": "Hansi Flick: La Rinascita del Barcellona", "category": "Sport", "tag": "Analisi", "excerpt": "Hansi Flick sta trasformando il Barcellona con un gioco verticale e aggressivo. Scopriamo come.", "img": "49d833e4-f356-48d2-a531-60976e4364ba.jfif", "fullText": "Articolo per il giornale “Postino”\nHansi Flick e il suo gioco\nIl gioco di Hansi Flick è uno dei più interessanti e curiosi d’Europa, ma chi è davvero? Hans Dieter Flick nasce in Germania, a Heidelberg, nel 1965. Intraprende la sua carriera calcistica nel 1985, al Bayern Munchen, dove trascorre cinque anni; il suo ruolo è sempre stato il centrocampista box to box, colui che sacrifica sempre il suo corpo per essere un guerriero in campo. Nel 1990 si trasferisce al Colonia, lì non trova continuità a causa di infortuni e poco minutaggio, inoltre non viene valorizzato, si ritira proprio a Colonia a causa dei continui infortuni. Comincia così, la sua carriera da tecnico al Victoria Bammental nel 1996 e va via dopo cinque stagioni. Dopo la prima esperienza viene preso dall’Hoffenheim nel 2000 e rende bene, avendo una durata di sei anni. Nel 2006 viene preso come vice del Salisburgo alle spalle di Trapattoni. In Austria ci rimane per un solo anno, poiché dal 2006 al 2014 acquisirà le conoscenze necessarie per diventare un ottimo tecnico; in questi anni, infatti, sarà un allievo di Löw, poiché sarà vice CT della Nazionale. Il 2019 sarà per lui l’anno della svolta perché verrà preso da Niko Kovač come suo vice nel Bayern München. Nell’estate di quell’annata, però, Kovač verrà esonerato e per due anni Hansi ricoprirà il ruolo di allenatore principale. Qui tutto il mondo si rende conto della potenza di questo allenatore, valorizzando calciatori come Goretzka e facendo vivere le migliori annate calcistiche di calciatori come Robert Lewandowski e Thomas Müller. Flick sarà conosciuto per le sue goleade, ad esempio come contro il Barcellona di Leo Messi ai quarti di Champions League, battuto per 8-2; in quell'anno poi Hansi si regalerà una Champions League, che non arrivava dal 2013, una Bundesliga, un Mondiale per club, una DFB-Pokal, una DFL-Supercup e una Supercoppa Europea, collezionando così il “SEXTUPLE” che fino ad allora aveva vinto soltanto Josep Guardiola nel 2009 con il Barcellona. Nel 2022 lascerà il posto, a causa di problemi con la dirigenza, a una persona che glielo ruberà anche in nazionale, parlo di Julian Nagelsmann. Dal 2024, Flick è tecnico del Barcellona, con cui finora ha vinto una Liga, una Copa Del Rey e due Supercopa. Ora però basta parlare di biografia e passiamo all'importanza del suo gioco e la mitica linea difensiva che la passata stagione gli è costata la finale di Champions League. Il suo gioco è uno dei più offensivi e aggressivi d'Europa,  ma come si sviluppa davvero? E come riesce a far valorizzare i suoi calciatori? La sua è un’evoluzione moderna con pressing alto e una rapida transizione offensiva. Partiamo dalla base, il modulo: un 4-3-3 che rapidamente in fase offensiva diventa un 2-4-4 o 2-1-3-4. Il suo gioco si concentra soprattutto con un possesso verticale; al posto del tiki taka utilizza una verticalità selettiva. I centrali difensivi si allargano e i terzini diventano ali, mentre la sua è una transizione veloce, appena persa la palla c'è un pressing ultra offensivo, chiamato Gegenpressing, che è asfissiante per tutte le squadre che lo affrontano.Sono fondamentali nel suo gioco soprattutto gli esterni, ecco perché Lamine Yamal e Raphinha sono diventati fondamentali e tra i migliori globali nel loro ruolo. Lui ha la capacità di valorizzare tutti i calciatori che servono per il suo gioco; proprio Raphinha con lui sta vivendo le annate migliori della sua carriera. Il suo gioco è concentrato anche sugli esterni con accentramento e tiro a rientrare o anche sovrapposizioni dei terzini, che diventano doppie ali. Un'altra causa per cui i calciatori rinascono con lui sono anche le alimentazioni e i carichi di lavoro. Secondo lui deve esserci una corretta e sana alimentazione con orari stabiliti per dormire; inoltre i suoi allenamenti sono concentrati su corse e sollevamento pesi in palestra, sul campo solo torelli ed esercizi con pressing altissimo. Una volta al mese le sue squadre utilizzano la maschera anti-ossigeno per effettuare una corsa e migliorare la propria capacità polmonare e respiratoria. Adesso parliamo della sua mitica linea difensiva. La difesa di Hansi Flick è quasi assente in ogni partita, o se c'è, è sempre alta. Questa tecnica può sembrare effettiva quando si imposta il gioco che si vuole e anche per far scattare il fuorigioco quasi sempre all'avversario che riceve una palla in profondità. Alcune volte però questa linea difensiva è stata calcolata male, di cui ha portato anche a opportunità sprecate, come nelle semifinali di Champions League della passata stagione contro l’Inter. Il Barça, infatti, ha subito gol calcolando male le distanze tra calciatore e avversario. L'Inter, che aveva un gioco che si sviluppava cercando quasi sempre i 2 attaccanti o gli esterni in profondità con lanci lunghi, ha saputo sfruttare bene l'errore degli avversari, facendo perdere la possibile vittoria della Champions al Barcellona. La manovra parte sempre dal basso, coinvolgendo molto il portiere e il centrocampista difensivo che si abbassa per ricevere palla e impostare il gioco verticalmente o orizzontalmente dalle ali. Il gioco di Flick è uno dei più offensivi attualmente in Europa e nel mondo, con una media di 2,45 gol a partita, la più alta d’Europa. Infine, Hansi è sempre stato un tecnico che non ha mai fallito con le squadre che ha allenato, escludendo la nazionale, di cui ha fallito alla Coppa del Mondo del 2022, uscendo ai gironi contro il Giappone.\nArticolo a cura di Antonio Guarracino"},
    {"title": "Il Parma e la presidenza Manenti", "category": "Sport", "tag": "Serie A", "excerpt": "Il ricordo della presidenza Manenti e il fallimento del Parma nel 2015.", "img": "manenti_profile.jpg", "fullText": "Articolo per il giornale “IL POSTINO”\nLa presidenza Manenti e il fallimento del Parma\n“di presentazioni sobrie ne ho viste tante, ma la sua, le batte tutte”.\nQuesta è una frase per chi, come me, ogni tanto non può fare a meno di rivedere una delle più iconiche e ridicole conferenze stampa del calcio italiano. Non stiamo, però, parlando né di un’ intervista a Ezio Capuano e nemmeno a Malesani, ma della conferenza stampa di presentazione di Giampietro Manenti, e sì, la frase iniziale puramente ironica da parte di un giornalista. Prima di arrivare al giorno della conferenza, dell’arresto e del fallimento, ripercorriamo chi è Manenti e la situazione di quel Parma.\nManenti, prima che “imprenditore”, è stato anche giocatore e allenatore. Come giocatore è passato per Milan, Avellino e Salernitana prima che un infortunio gli spezzasse la carriera, non che fosse così promettente. E’ poi diventato allenatore a livelli provinciali. E’ titolare della MAPI, società che ha sede a Nova Gorica, in Slovenia.\nIl Parma veniva da un’ottima stagione, un ottimo 6° posto e teoricamente qualificata all’Europa League, ma di questo “teoricamente” ne parliamo a breve. Nel dietro le quinte di quel Parma, però, giocatori e staff già non stavano percependo stipendio e il Parma aveva un debito da quantomeno 100 milioni. Ritornando all’Europa League, la non iscrizione del parma all’edizione dell’anno fu la goccia che fece traboccare il vaso e il presidente Tommaso Ghirardi fu costretto ad andarsene. La società passò a Fabio Giordano, in panchina arrivò Donadoni, che poco riuscì a fare sul campo, con la situazione societaria che si rifletteva sul campo, e Parma all’ultimo posto. A gennaio 2015 i crociati hanno un nuovo cambio ai vertici, in particolare la squadra fu acquistata da una holding Cipriota, che faceva riferimento a Ermir Kodra. Da questo punto è tutta una caduta libera, alcuni giocatori, tra cui Antonio Cassano, rescissero il proprio contratto. Il 6 febbraio 2015 c’è l’ufficialità, Giampietro Manenti è il nuovo presidente del Parma, per la cifra simbolica di 1 euro.\nI tifosi inizialmente lo accolgono con speranza, è l’ultima barca per non fallire. Un primo problema si presenta subito, ci si aspettava che la nuova presidenza emettesse immediatamente dei bonifici per evitare delle penalizzazioni, ma non arriva nulla. Il giorno della conferenza stampa di presentazione è probabilmente il giorno dove si è capito che il Parma stava per fallire, Manenti si presenta con una giacca aperta color marroncino e una camicia azzurra che nel totale creavano un look che definire trasandato e poco curato è un complimento. Non si presenta da solo, con lui, i manager Alborghetti. I due rispondono alle domande in modo supponente, in difensiva, quasi offesi dal fatto che si avesse dubbi su di loro.\nLe prime domande sono sul da dove partano i fondi del presidente, il quale cita MAPI group, che sarebbe , a detta sua, in collaborazione con banche internazionali. Chiaramente MAPI in realta è solo una grossa scatola vuota, ma a detta di Manenti avrebbe avuto anche varie branchie, tra le quali gastronomia, industria e fashion. Altra domanda era relativa ai primi bonifici e quando sarebbero arrivati. Il Parma aveva una data di scadenza , datata 16 febbraio, per dimostrare la propria stabilità e disponibilità bancaria, senza illeciti, oltre che altri fondi da pagare anche prima,altrimenti penalizzazione. Manenti riguardo a ciò pare sicuro, i soldi arriveranno entro il 16 e nei giorni successivi già i primi stipendi. La preoccupazione del neo-presidente e del manager Alborghetti sembra più la retrocessione in serie b. Iconico lo scontro tra Manenti e il giornalista Gereviri, che lo accusò di tutto, dai fondi alla serietà del progetto, Manenti, però, sempre con supponenza, si difende. Nei giorni seguenti i soldi non arrivano, il Parma riceve i primi punti di penalizzazione e Manenti viene persino aggredito da un ultras disperato del Parma.\nAlla fine, il 18 marzo 2015, Manenti e altre 22 persone vengono arrestate per crimini vari, tra cui associazione a delinquere. Il giorno seguente il Parma è dichiarato fallito e ripartirà dalla serie d dell’anno dopo, con in panchina Nevio Scala, che vincerà la serie dilettantistica da imbattuto. Manenti rimarrà a San Vittore per poco più di due settimane, continuerà a professarsi innocente ed oggi è consulente in aziende Europee. Della MAPI c’è poco da dire, la holding che investiva sulla MAPI per farne nascere altre branchie è fallita e MSAPI rimane una scatola vuota quanto fittizia. Oggi il parma è in serie a, senza debiti e con giocatori e staff stipendiati, sfornando ogni anno talenti interessanti.\nMorale della favola, non avremo mai l’onore di vestire MAPI fashion, anche se, vedendo Manenti, non credo che fosse chissà che intenditore.  \nArticolo a cura di Christian Corrado"},
    {"title": "Il Maracanazo: Una Ferita Aperta", "category": "Sport", "tag": "Storia", "excerpt": "Il 16 luglio 1950 il Brasile perse il Mondiale in casa contro l'Uruguay.", "img": "maracanazo_history.jpg", "fullText": "Il Maracanazo\nBeauty is great for the spectators, but fight and determination win matches – La bellezza è ottima per gli spettatori, ma la lotta e la determinazione vincono le partite. Questa è la frase pronunciata da Obduldio Varela, capitano dell’Uruguay, dopo una delle partite più tragiche nell’intera storia del Brasile, ma una delle più sorprendenti nella storia dei Mondiali di calcio. \nPer capirne il motivo, bisogna ritornare indietro nel tempo al 16 luglio 1950, giorno della quarta finale della Coppa del Mondo.\nLe squadre finaliste sono il Brasile e l’Uruguay: la prima è la squadra ospitante ed è arrivata in finale senza perdere una partita, mentre l’Uruguay ha perso diversi punti per strada.\nBisogna specificare che il formato dei Mondiali del 1950 era diverso rispetto a quello attuale. Nella fase finale c’erano quattro squadre: Brasile, Uruguay, Svezia e Spagna. Il Brasile aveva vinto per 7 a 1 contro la Svezia e 6 a 1 contro la Spagna, mentre l’Uruguay aveva pareggiato a fatica con il risultato di 2 a 2 contro la Spagna e vinto 3 a 2 contro la Svezia, di conseguenza il Brasile aveva 4 punti mentre l’Uruguay ne aveva 3, quindi al Brasile serviva un pareggio per laurearsi Campione del Mondo. \nPer questo motivo, la mattina del 16 luglio a Rio de Jainero c’è aria di festa: carri, danze, per tutto il paese il Brasile è campione del mondo, ma nel calcio non si deve mai sottovalutare l’avversario.\nSpostiamoci alla partita: sera del 16 luglio, Stadio Maracanà di Rio de Janeiro, i tifosi brasiliani sono 200.000 (record assoluto nella storia del  calcio), mentre i tifosi uruguayani sono solamente 100. \nMolti di voi si stanno chiedendo : l’Uruguay era veramente così scarso? Assolutamente no!\nSi presenta al Maracanà schierando questa formazione: Maspoli in porta, in difesa Gonzales e Tejera, a centrocampo Gambetta, Varela (il capitano, detto “il capo”) e Rodriguez Andrade, in attacco Ghiggia (detto “la volpe”), Perez, Miguel, Schiaffino (detto “il Dio del calcio”) e Moran. \nNon può essere definita scarsa una squadra che ha in campo il “Dio del calcio” …\nIl Brasile invece schiera Barbosa in porta, in difesa Augusto, Juvenal, Bauer e Danilo, a centrocampo Bigode e Friaca, in attacco Zizinho, Ademir (capocannoniere con 8 gol), Jair e Chico.\nLa partita inizia con un boato, che sarà considerato il più grande mai sentito durante una partita di calcio.\nIl Brasile attacca mentre l’Uruguay difende con le unghie, marcando addirittura in due l’attaccante brasiliano Ademir.\nNonostante le varie conclusioni verso la porta dell’Uruguay, il primo tempo finisce 0-0, con un pizzico di delusione da parte dei 200.000 tifosi presenti al Maracanà ma, per fortuna loro, il muro dell’Uruguay cade solo dopo 68 secondi dall’inizio del secondo tempo. Ademir fugge sulla fascia e serve a Friaca che, in diagonale batte Maspoli, 1-0 Brasile. \nSembra l’inizio del sogno, ma in realtà è l’inizio dell’incubo. Al 66’ la Volpe Ghiggia scappa sulla fascia e mette un cross perfetto sulla testa di Schiaffino che prima addomestica la palla e poi calcia all’incrocio, 1-1.\nNonostante il gol subito, c’è ancora aria di festa, perché il pareggio va bene per il Brasile, ma l’Uruguay ne ha ancora. Al 79’ Ghiggia scappa ancora sulla fascia: il portiere brasiliano Barbosa, aspettandosi il cross, si muove verso il secondo palo ma Ghiggia lo beffa, calciando sul primo… 2-1 Uruguay. \nIl Maracanà cala in un silenzio impressionante, mancano ancora 10 minuti più recupero, ma il Brasile non ne ha più! Finisce 2 a 1 per l’Uruguay. \nGhiggia, dopo la partita, dirà: “Solo tre persone hanno zittito il Maracanà, Frank Sinatra, Papa Giovanni Paolo II ed io .”\nPer il Brasile è una tragedia: 8 persone morte, 34  suicidi e 169 persone hanno avuto malori, anche i giocatori subiranno le conseguenze della sconfitta, l’ala Zizinho riceverà ogni 16 luglio una telefonata anonima che reciterà: “Perché abbiamo perso?” mentre il portiere Barbosa, considerato il principale colpevole, dirà: “In Brasile, la pena massima per un crimine è 30 anni. Io ne sto scontando più di 40 per un crimine che non ho commesso”.\nAl popolo, invece, le lacrime verranno cancellate da cinque future vittorie dei campionati mondiali, ma per sempre rimarrà la tragedia di una finale che era considerata già vinta.\nArticolo a cura di Francesco Castiglione"},
    {"title": "Cime Tempestose: Una Recensione", "category": "Cinema", "tag": "Recensione", "excerpt": "Il nuovo film diretto da Emerald Fennell che riprende il romanzo di Emily Bronte.", "img": "b6b5b384-4888-446b-a84e-fdd7069d6ac3.jfif", "fullText": "Cime Tempestose – Bozza – Redazione Cinema\nUn altro dei film che tratteremo è il nuovo “Cime Tempestose” diretto da Emerald Fennell che riprende la storia del famoso romanzo scritto da Emily Bronte, considerato uno dei romanzi più importanti della letteratura inglese oltre ad essere anche il mio preferito. Questa nuova versione prova a rendere la storia ancora più complicata dal punto di vista dei sentimenti. La storia racconta il rapporto molto complicato tra Heathcliff e Catherine, due ragazzi che crescono insieme fin da piccoli. Heathcliff, infatti, non è il vero figlio della famiglia ma viene trovato per strada dal padre di Catherine che decide di adottarlo e portarlo a vivere con la famiglia. All’inizio il padre di Catherine cioè il padrone della casa, inizia a trattare Heathcliff in modo duro , costringendolo a fare lavori pesanti e umiliandolo. Nonostante questo Catherine continua a passare molto tempo con lui e tra i due nasce un legame molto forte. Crescendo però Catherine conosce un’altra famiglia più ricca, quella dei Linton, dove incontra Edgar e sua sorella Isabella. Edgar si innamora subito di Catherine e gli promette una vita più sicura e tranquilla dal punto di vista economico e per questo Catherine decide di sposarlo anche se dentro di sé continua ad amare Heathcliff. Quando Heathcliff scopre questa decisione rimane molto offeso e decide di scappare. Dopo anni ritorna, più elegante e con un aspetto principesco, ma dentro gli rimane la rabbia. Nel frattempo anche Isabella si innamora di Heathcliff, però questo amore non sarà felice e ci fa vedere quanto Heathcliff é diventato sempre più duro. Catherine nel frattempo è sposata con Edgar e rimane incinta, ma dopo un periodo di grande stress si ammala e perde il bambino.  La sua salute peggiora anche a causa di suo marito e Heathcliff, fino alla morte di Catherine. Il rapporto tra Heathcliff e Catherine è importante anche se ci sono stati vari conflitti. Heathcliff compie anche dei gesti nei confronti di Catherine, uno dei più significativi è quando rompe una sedia del tavolo per accendere il fuoco e scaldarla mentre lei sta male. L’aspetto importante è che quella sedia rappresenta il suo posto a tavola e romperla significa togliere il proprio posto pur di riscaldarla. Un altro personaggio molto importante è la serva Nelly, ex serva del padre di Catherine , che giudica Catherine in modo duro, e colpevole della morte di Catherine poiché non ha riferito alla famiglia di aver perso il bambino, forse per gelosia. Proprio per questo Cime Tempestose è diverso da molti altri romanzi romantici dell’epoca perché non é un amore perfetto ma un amore tormentato da una serie di eventi."},
    {"title": "Scuola e videogiochi, opposti o coincidenti?", "category": "Videogiochi", "tag": "Riflessione", "excerpt": "Una riflessione su come i videogiochi come Uncharted possano essere educativi.", "img": "87e20958-928b-4d25-9252-120d9f99c40e.jfif", "fullText": "Articolo \nGiornale Postino\nSede Marano (NA 80016)\nPOSTINO\nScuola e videogiochi, opposti o coincidenti?\nLa risposta breve è NO!\nAd oggi un pò siamo “videoludici”.\nGiochiamo per svago, per divertirci, per acculturarci e per ciò che ci insegnano. Si, anche per ciò che ci insegnano, non solo dal punto di vista emotivo, ma anche da quello culturale e storico.\nCi sono tanti capolavori videoludici, un esempio concreto è la saga di Uncharted, nata nel 2007 per opera di Naughty Dog, casa costruttrice di proprietà Sony.\nIl primo Uncharted è Drake’s Fortune, ci troviamo nei panni di Nathan Drake, un ragazzino cresciuto in un orfanotrofio insieme al fratello maggiore Sam Drake, per la prima volta nel quarto ed ultimo gioco della saga con protagonista Nathan Drake “La fine di un ladro”.\nNathan, una volta aver abbandonato l’orfanotrofio (ormai adolescente), verrà cresciuto da Victor Sullivan (Sully) (Uncharted 3), a seguito di un borseggio per l’anello di Sir Francis Drake, pirata vissuto intorno al 1540 d.C, in Inghilterra.  Da quest’ultimo si ispira proprio il personaggio di Nathan e si unisce la storia con lo svago di noi giovani. I più attenti sapranno che Sir Francis non aveva eredi; infatti, nell’ultimo titolo della saga si scoprirà che dopo essersi intrufolati all’interno di una casa, dove la mamma (Cassandra Morgan) ha lavorato anni e anni prima e aveva lasciato delle cose a cui i fratelli Drake erano affezionati e volevano riprendersi, scapperanno dalla polizia e cambieranno identità, dai fratelli Morgan ai fratelli Drake.\nBrevemente vi racconterò i 4 giochi della saga.\nNel primo gioco della saga dobbiamo riportare alla luce la mitica città di El Dorado con tutto il suo oro maledetto, appartiene alla mitologia e al folklore sudamericano.\nNel secondo gioco, dopo aver subito un tradimento da un vecchio amico, dobbiamo sterminare l’esercito di Flynn e Zoran Lazarević per trovare la via di Shambala, mito asiatico legato alla spiritualità buddhista e a un regno nascosto.\nNel terzo gioco dobbiamo trovare il tesoro di Thomas Edward Lawrence, conosciuto meglio come Lawrence D’Arabia (Durante la guerra era un ufficiale britannico che operava nel Medio Oriente. Collaborò con i ribelli arabi nella ArabRevolt, una rivolta contro l’Impero Ottomano.), ma a seguito di un problema con l’ex di Sully (anche essa impegnata nella caccia a tesoro), si troveranno entrambi su un aereo che precipiterà sul deserto del Rub al Khali (Ubar), trovando per pura casualità la città fantasma e abbandonata dopo la pri ma guerra mondiale.\nNel quarto gioco della saga, ci troviamo in prigione con Sam ed un loro caro amico conosciuto lì, Rafe Adler.I tre effettueranno una fuga, ma Sam verrà sparato e Nathan ormai lo dà per morto, ma il gioco ci porta 15 anni più avanti, dopo questi 15 anni Nathan se lo ritroverà alla porta di casa.\nSam sa bene che Nathan aveva chiuso con i tesori e quindi per convincerlo a cercare il tesoro che da piccoli hanno sognato e studiato (anche grazie ai libri della mamma archeologa ritrovati in quella casa) di Henry Avery e la colonia di Libertalia fondata da vari pirati inventa che un boss l’ha fatto evadere dal carcere ed ora vuole parte di quel tesoro.\nIn seguito, Nathan sulla via per il tesoro incontrerà Rafe (che si rileverà essere un loro nemico) e quest’ultimo dirà tutta la verità a Nathan davanti a Sam, cioè che quel boss era morto da anni e Rafe aveva pagato la cauzione a Sam ma senza voler nulla in cambio, gli aveva chiesto solo di non intromettersi in questa vicenda del tesoro. \nUncharted è un pezzo d’infanzia che è nel cuore di tutti noi giocatori, potrei rigiocarlo un milione di volte senza mai stancarmi, la storia dei pirati, di Drake, Avery, Anne Bonny ed altri merita di essere studiata, lo studio merita di essere collegato allo svago, alle passioni e alla gioia di noi giovani adolescenti.\nUn altro esempio concreto è la saga di Assassin’s Creed, creata da Ubisoft nel 2007, leggermente prima di Uncharted. Attualmente i capitoli principali sono 14, ma con gli spin-off si arriva anche a 20.\nAd esempio, nella saga Ezio Collection ci troviamo nel medioevo rinascimentale, nei panni di un giovane di nome Ezio Auditore, originario della repubblica fiorentina (Firenze).\nEzio all’inizio non è un assassino, lo diventerà in seguito alla morte del padre e dei due fratelli, impiccati ingiustamente davanti al pubblico di Firenze e traditi dall’avvocato Umberto corrotto dalla famiglia rivale De Pazzi. Nel gioco incontreremo vari personaggi storici, tra i più celebri troviamo Leonardo da Vinci, un caro amico di Ezio, così tanto da prestargli armi che realmente ha creato lui. Successivamente Ezio verrà incaricato dalla madre Maria di proteggere la famiglia De Medici, con a capo Lorenzo De Medici, detto il magnifico. \nEzio diventerà un assassino per portare avanti la dinastia e la confraternita degli assassini, spiegata bene in Assassin’s Creed Origins.\nAssassin’s Creed Odyssey invece è ambientato nell’antica Grecia (V secolo a.C), un titolo molto dettagliato di cui si impara tantissimo su tutta la mitologia greca. \nQuesti giochi oltre a storie mitologiche e medievali mi hanno insegnato personalmente i valori nell’amare una persona che merita veramente.\nSi, è ovvio che giocare tanto può nuocere alla salute o comunque può “incollarci ad uno schermo”, ma con moderazione ed unita magari allo studio o comunque al nostro bagaglio culturale può migliorare, concentrazione, logica ma soprattutto la voglia di studiare.\nIn conclusione? Spero che quest’articolo che ho scritto con tanta voglia e passione lo legga qualche prof per unire studio e divertimento, mi piacerebbe davvero tanto sentire qualche prof che colleghi queste due cose, inoltre mi sento di consigliare agli studenti di giocare titoli che possano farci imparare qualcosa, non solo di storia, ma emotivamente, non solo i titoli che ho citato in questo articolo, ma anche titoli come:\nGod of War, Call of duty (consiglio il WWII), Kindom Come Deliverance, anche Detroit Become Human, ma soprattutto il mio preferito Red Dead Redemption II.\nN.B\nLa saga di Uncharted oltre a questi titoli di cui vi ho parlato comprende anche Golden Abyss, uscito nel 2011/2012 Drake’s Fortune, dove Nathan sarà alla ricerca della città d’oro di Quivirasulle montagne dell’america centrale (le sette città dell’oro).\nNell’ultimo capitolo di tutta la saga “L’eredità perduta” (The lost Legacy) ci troviamo nei panni di Chloe Frazer, ex di Nathan, che alleata con Nadine Ross (nemica dei fratelli Drake in Uncharted 4 e alleata di Rafe Adler), dovrà trovare la zanna di Ganesh per poi salvare Sam Drake nonostante l’odio con Ross, si impara molto sulla mitologia indiana.\nVi lascio con qualche frase iconica delle due saghe di cui vi ho parlato:\n“Tutti gli uomini sognano, ma non tutti allo stesso modo. Coloro che sognano di notte, nei polverosi recessi della mente, si svegliano al giorno seguente scoprendo che era solo vanità; ma i sognatori diurni sono uomini pericolosi, perché possono agire il loro sogno a occhi aperti, rendendolo possibile. Questo l’ho fatto io.” \n“Fai attenzione a ciò che desideri. Potresti ottenerlo davvero.”\nNathan Drake.\nSIC PARVIS MAGNA (motto di Sir Francis Drake)\n“Nulla è vero, tutto è lecito”\n“Reagisci, impara, migliora. Non c’è altro modo.”\nEzio Auditore."},
    {"title": "La Bellavita di Artie 5ive", "category": "Musica", "tag": "Recensione Album", "excerpt": "Recensione dell'album 'La Bellavita' pubblicato nel 2025.", "img": "5e7b36fc-95b0-4cb1-afcc-89e43938d108.jfif", "fullText": "LA BELLAVITA\nLa Bellavita di Artie 5ive è un progetto che espone la fame del successo dell’artista. Il titolo dell’album rappresenta l’obbiettivo che ha raggiunto il cantante. Quest’album è stato pubblicato nel 2025 e ha collezionato ben 2 dischi di platino. Andiamo a vedere le varie tracce:\nLa prima traccia è “Intro” e riflette sulla ricerca di una vita lussuosa e sulla sua crescita personale rappresentando i suoi cambiamenti (“la bellavita sulle colline”)\nLa seconda traccia è “Montecarlo” in cui utilizza la località citata nel titolo per dimostrare il raggiungimento di una vita agiata grazie alla musica, siccome Montecarlo è una città molto ricca \nLa terza traccia è “Brazy”, in questo brano troviamo il feat con Tony Boy, tra questa canzone e quella precedente, ossia Montecarlo, troviamo una transition che li lega, dal punto di vista del significato non ne ha uno preciso ma è per lo più per “gasare”, ed è molto simile al genere americano\nLa quarta traccia è “Ogni amico mio” in cui racconta della vita dell’artista dal punto di vista dell’amicizia, in quanto nonostante che lui e i suoi amici non avevano niente sono rimasti sempre uniti.\nLa quinta traccia è “Sogno americano”, in questa traccia l’artista esprime il motivo di rivalsa personale raccontando il suo percorso di vita \nLa sesta traccia è “FW/SS25, su questo brano possiamo dire che celebra il successo, ma niente di che siccome si tratta di un freestyle\nLa settima traccia è “Tu”, si tratta di una canzone che parla d’amore e l’artista esprime il concetto di una brutta relazione, in quanto lui viene sempre preso per il cattivo della situazione \nL’ottava traccia è “Are U Crazy?” per quanto mi riguarda è la melodia più bella che abbia mai sentito in vitamia, il ritornello è forte e ripetuto con alternanza tra Artie 5ive e CapoPlaza, artista con cui ha fatto il feat, e continua a rappresentare “Tu” ma parla dell’aspetto più bello.\nLa nona traccia è “Dodge Durango” un po' per come è avvenuto per il titolo della canzone “Montecarlo” anche questa canzone l’artista prende spunto da un esempio reale, in questo caso la dodge durango che sarebbe una macchina abbastanza costosa, per esprimere la sua ricchezza e popolarità\nLa decima traccia è “Litorale”, una canzone con cui troviamo il feat con Guè, questa canzone esprime l’umiltà dell’artista e racconta che molti rapper vengono presi per dei gangstar, ma lui si definisce come un imprenditore “Sono rapper però apro due aziende”\nL’undicesima traccia è “Davverodavvero”, in questa traccia l’artista esprime il momento in cui riesce a raggiungere il successo, citando anche da dove viene\nLa dodicesima traccia è “Milano Ferragosto”, in questo brano l’artista fa riferimento alla città di Milano a ferragosto, quando la città è deserta, e utilizza ciò come una metafora in quanto l’artista si sente vuoto e solo nonostante il successo.\nLa tredicesima traccia è “Pietà”, in questa traccia troviamo il feat con kid yugi, parla principalmente del comportamento di alcune persone che si vantano o comunque si sentono superiori nonostante non abbiano nulla mentre Artie 5ive nonostante la sua ricchezza e popolarità rimane comunque umile. Per esprimere tutto ciò troviamo anche alcune barre in cui si evidenzia l’aspetto religioso “Dio,perdona,abbi pietà” \nLa quattordicesima traccia è “Milano Testarossa”, in questa canzone troviamo nuovamente il feat di Guè, e dal punto di vista del significato l’artista esprime la sua popolarità mettendo spesso in evidenzia il colore rosso, colore simbolo dell’artista \nLa quindicesima traccia è “00”, questa canzone ha raggiunto la settima posizione della classifica italiana, grazie al suo ritmo intenso. Parla di come l’artista ha imparato a guadagnare così tanto affrontando anche altri temi come: la povertà, violenza e discriminazione."},
    {"title": "Anche gli eroi muoiono - Kid Yugi", "category": "Musica", "tag": "Recensione Album", "excerpt": "Il ritorno di Kid Yugi con un album crudo e introspettivo.", "img": "8d8e509c-61fc-4221-9be2-bab2057a5e86.jfif", "fullText": "RECENSIONE: ANCHE GLI EROI MUOIONO - KID YUGI\nFrancesco Stasi in arte Kid Yugi, rapper pugliese che ci mette tutto se stesso per farsi capire, è alto due metri, ha scritto il suo primo album \"The globe\" (2022) poi Quarto di bue (2023) e “Tutti i nomi del diavolo” (2024). Dopo \"tutti i nomi del diavolo\" si prende un anno di pausa e torna con questo capolavoro intitolato \"Anche gli eroi muoiono\" l'album comincia con \"L'ultimo a cadere\" una canzone dove lui parla di alcuni insuccessi e cercherà di essere l'ultimo a cadere. Questa canzone a me non piace perché si sente troppo autotune, dopodiché troviamo subito un featuring con Shiva intitolata: \"la violenza necessaria\" Il pezzo con Shiva è eccezionale perché è crudo e va dritto al punto. L’autore non fa troppi giri di parole e dice chiaramente che in certi posti o mangi o vieni mangiato, e che a volte alzare la voce o fare la faccia tosta è l'unico modo per non farsi mettere i piedi in testa.\nLa terza traccia si chiama Eroina feat tutti i fenomeni una canzone più concentrata sull'amore dove menziona la parola Eroina e Cocaina per questo ha suscitato uno scandalo alla radio, perché davanti ai soldi non è riuscito a trattenersi e ha cambiato la parola medicina.\ne poi procediamo con la quarta intitolata \"Jolly\" il ritornello dice: “Il mio credo è soldi, soldi, soldi, mentre voi ammazzate lo scappo con i lingotti”. E dice che ora è il tempo dei soldi come se minimizzasse l'essere umano. La quinta traccia è un feat questa volta con Tony Boy intitolata: “Mostro” dove parlano delle loro ex frequentazioni/fidanzamenti che li hanno resi dei mostri e dicono che anche quest'ultimi soffrono. La sesta traccia è stata il primo spoiler prima che uscisse l'album della pura rap intitolata: “Berserker” mi piace molto e cita Belen, De André e Ken di barbie. La settima è un altro feat con Anna in \"Push it\", sempre rap, menziona la sua ex ed è stata la seconda canzone spoilerata prima dell'uscita dell'album. L'ottava è \"Amelie\" ,che io non preferisco, ed è una canzone dedicata ad una ragazza conosciuta a Parigi ma che non si chiama Amelie. La decima traccia è “Gilgamesh” un’ altra canzone pura rap cita Ginnor, Checco e Justin Bieber con Clay Thompson.\nNell'undicesima traccia troviamo “Chuck Morris” un altro feat con Papa V e Rrari dal Tacco, una curiosità su questa canzone è che ha la parte finale è tutta in pugliese.  La dodicesima si chiama \"Tristano e Isotta\" ispirata allo storico romanzo di Chretien de Troyes o di Beroul e in una barra dice \"Il nostro amore che ci uccide alla Tristano e Isotta\" io la amo ed è una delle mie preferite. La prossima è \"Mu'ammar Gheddafi\" si rifà al colonnello e dittatore della Libia anche questa è un feat con Simba la Rue. La prossima troviamo l'ultimo feat, con Artie 5ive: “bullet ballet”, puro rap, ed  la mia preferita. Anne Frank e l'idi di marzo. La quattordicesima intitolata \"per il sangue versato\" una canzone che parla di due ragazzi di due quartieri diversi evidenziando la differenza tra le loro vite.\nla penultima traccia si chiama \"Per te che lotto\" dedicata ad una ragazza per cui prova un amore cosi forte e che lotterebbe per quest’ultimo. L'ultima, la più bella, \"Davide e Golia\" ispirato al racconto biblico del più forte contro il più debole, tratta molti argomenti come: guerra, prigione, attori, bomba nucleare, dieta, tossici e molti altri. Questo è il mio album preferito vi consiglio di ascoltarlo grazie dell'attenzione.\nTRACKLIST & BIO\n1. L'ultimo a cadere\n2. La violenza necessaria (feat shiva)\n3. Eroina (feat tutti i fenomeni)\n4. Jolly\n5. Mostro (feat tony boy)\n6. Berserker\n7. Push it (feat Anna)\n8. Amelie\n9. Gilgamesh\n10. Chuck Norris (feat Papa V e RRari dal tacco)\n11. Tristano e Isotta\n12. Mu'ammar Gheddafi (feat Simba la rue)\n13. Bullet Ballet (feat Artie 5ive)\n14. Per il sangue versato\n15. Per te che lotto\n16. Davide e Golia"},
    {"title": "Dolce Vita - Shiva", "category": "Musica", "tag": "Recensione Album", "excerpt": "L'album della rivincita di Shiva pubblicato nel 2021.", "img": "0ee88205-fa7f-40d1-afd2-0966d7a6f364.jfif", "fullText": "Dolce vita è il terzo album in studio del rapper italiano Shiva, pubblicato l’11 giugno 2021 dalla Milano Ovest (la sua casa discografica). Dura esattamente 42 minuti, con 14 tracce, di cui 2 solo in digitale (fendi belt –feat paky- e non sai niente –feat Gue-), etichettato da Sony Musica, Columbia e da Milano Ovest. Certificato solo una volta disco di platino con +50000 di ascoltatori. Si è classificato sesto nella classifica del 2021. Shiva classe del 99, fra il 2014 e il 2017, si afferma come “next big thing” del rap italiano, inizia a fare le prime collaborazioni, la più importante è stata quella con Honiro. Nel 2019 inizia il suo boom, iniziando a fare anche collaborazioni importanti, ad esempio Emis Killa e Sfera Ebbasta. Nel 2020 non riesce più ad avere reputazione, gli ascoltatori iniziano a calare e diventa un anno difficile. Dolce vita diventa l’album della rivincita, l’album che ancora per una volta dimostra la sua bravura.\nTRACCE\nDolce vita\nI can fly\nMastercard (feat Lil Baby)\nIdee chiare\nCollane e bugie\nSuperstar\nMegatron\nProblema\nLa mia storia (singolo)\n Montecarlo\nHi-Tech Freestyle\nIl diavolo chiama\nFendi belt (feat Paky)\nNon sai niente (feat Geolier)\nDoolce vita, la prima traccia dell’album, colpisce perché sin da subito, il cantante, parla della sua rivincita, di come dal niente è diventato così importante. Il sound è molto forte, fa capire con quanta forza lui vuole riprendersi quello che ha perso per poco tempo. I can fly, stesso il titolo di questa seconda traccia può farci capire molte cose, “io posso volare”, racconta che dalle strade e dal niente arriva a girare su macchine di lusso. Tante persone non credevano in lui, ma non ha mai mollato e ci ha sempre creduto. Il beat è molto calmo ma a tratti forte e attira molto l’attenzione. Mastercard (feat Lil Baby), terza traccia, una delle più importanti internazionali di Shiva, a livello di stereografia non ha qualcosa da raccontare. Parla di droga, armi, macchine… Il feat con Lil Baby è sicuramente importante e soprattutto dà quel tocco di attrazione. Idee chiare, quarta traccia , una delle più belle dell’album, un amore incondizionato per lui, di come è oggi e di come vuole esserlo per le persone che ha affianco. Racconta di come tanti ragazzi della sua età, per fare le sue stesse cose sono morte senza sapere il perché. Il beat è molto calmo, quasi rilassante. Collane e bugie, quinta traccia, parla dal come, Shiva, è passato ad avere niente ad avere catene molto costose e pesanti. Di come è abituato a sopravvivere per strada e a non dire bugie. Il beat accompagna il tutto perfettamente con la voce. Superstar, sesta traccia, il cantante parla del suo percorso verso il successo, parla di come è arrivato al lusso. Ma ovviamente la fama non porta solo soldi, ma anche la solitudine e le persone false. Con un beat molto quasi malinconico, che accompagna la storia. Megatron, settima traccia, Shiva si rappresenta come il Megatron, ovvero il capo dei Decepticon, un gladiatore molto forte. Usa un beat delle canzoni trapper, quindi molto forte. Problema, ottava traccia, parla di sfide che il rapper ha dovuto affrontare, la resistenza che lui ha avuto per la sua vita, con un beat molto aggressivo e coinvolgente. La mia storia, nona traccia, una delle più significative, con un beet lento, Shiva ci racconta della sua storia, del come è vissuto nelle strade di Corsico e di come ha vissuto senza un padre."},
    {"title": "Heroes & Villains - Metro Boomin", "category": "Musica", "tag": "Recensione Album", "excerpt": "Un viaggio cinematografico tra eroi e cattivi.", "img": "8d0b2472-63a9-4251-92ea-2f468cb2595e.jfif", "fullText": "HEROES & VILLAINS Nel 2021, Metro ha pubblicato il titolo dell’album attraverso una lettera scritta da DJ Holiday per inaugurare il terzo anniversario del suo album. Il 16 dicembre 2022 nel suo 29° compleanno ha “droppato” il video trailer nel quale vengono presentati tutti i “featuring”. Però ci fu un problema, cioè che l’album venne rimandato a causa delle liquidazioni dei campioni, anche se i fan pensavano che fosse a causa del \n\n“drop” dell’album congiunto tra Drake e 21Savage. L’album all’uscita andò subito virale, siccome sono presenti i migliori cantanti americani di quel periodo e anche grazie alla presenza di Travis Scott che non “droppava” dal 2018 a causa anche dello scandalo di Astroworld dove ci furono centinaia di morti e feriti. L'album nel 2023 è stato quello con più copie vendute e più ascoltato. ON TIME (CON JOHN LEGEND) La prima traccia, On time, è quella che introduce l’album. Piuttosto di una semplice canzone è una traccia cinematografica perché c’è solo la divisione tra HEROES & VILLAINS (eroi e cattivi) e poi a fine traccia si può notare che c’è una transizione, la quale introduce la seconda traccia, Superhero. SUPERHERO (CON FUTURE E CHRIS BROWN) La seconda traccia dell’album è Superhero, “Supereroi”. Questo termine descrive un po’ la vita di Future dove viene raccontata nella sua parte dove parla del fatto che tutti sono contro di lui e li ha dovuti affrontare e superare le proprie difficolta, ma non solo, perché i Supereroi sono coloro che hanno molti soldi che di fatto attraggono le donne attorno a loro. Ma fa capire anche che la loro vita è movimentata e non poco ed è soprattutto basata sulla vita notturna, descritta in Too Many Nights. TOO MANY NIGHTS (CON FUTURE E DON TOLIVER) Too many nights è la terza traccia, molto in “hype” grazie al beat rilassante che combacia con lo stile di Future. Si parla sempre degli stessi argomenti\n\ntipo i soldi, donne, diamanti e festini. Ma il significato del titolo, “Troppe notti”, è che lui ha passato così tante notti a lavorare che la sua stanchezza lo ha portato allo sfinimento. RAINDROPS (CON TRAVIS SCOTT) Raindrops è la quarta traccia, anche essa in “hype” ma per motivo diverso, la presenza di Travis Scott, il quale non “droppava” nulla dal 2018. Gli argomenti? Non cambiano, difatti sono sempre i soldi, presenti in tutte le tracce, come argomento principale ma non solo perché Raindrops significa pioggia ma non quella normale ma “pioggia di diamanti” inerente quindi alla ricchezza ottenuta grazie al successo. TRANCE (CON TRAVIS SCOTT E YOUNG THUG) Trance è la sesta traccia dell’album, superato il miliardo di ascolti. Trance, significa “stato di trance” cioè quando sei attratto da qualcuno o qualcosa oppure quando qualcuno è attratto da te, infatti in questa canzone si parla di un’attrazione da una ragazza o lei che è attratta da lui. Certamente, l’attrazione non è solo estetica ma anche per la ricchezza e per il successo che andrebbe solo a migliorarle la vita. AROUND ME (CON DON TOLIVER) Settima traccia, Around me, “intorno a me”, rappresenta tutte le persone che adesso sono vicine a lui solo per la sua ricchezza e il suo successo ma nei momenti bui, di queste persone, chi era già presente? Di certo non è solo questo il significato ma anche tutto quello che ha intorno a lui, in quale contesto si trova, ma anche tutti i suoi fan che lo hanno accompagnato per tutta la sua carriera seguendolo sempre. CREEPIN’ (CON THE WEEKND E 21SAVAGE) Decima traccia, la più ascoltata, anche grazie la presenza di The Weekend, il cantante con più ascoltatori mensili al mondo. Creepin’ significa \n\n“muoversi di nascosto” intendendo che la loro vita è basata soprattutto sulla segretezza delle attività che svolgono siccome loro difficilmente hanno una vita privata siccome saranno sempre seguiti dai loro fan. Certamente, citazioni come i soldi non possono mancare come anche il lusso, la vita da milionari, i soliti festini e la vita notturna. Ma parla anche di\n\nvarie difficoltà presenti nelle relazioni definite “tossiche” come il tradimento, il sospetto e la mancanza di fiducia. ALL THE MONEY (CON GUNNA) Ultima traccia, rappresenta tutto quello citato in precedenza nell’album, i soldi sono presenti anche in questa traccia, e viene detto in che modo vengono utilizzati questi soldi, spendendoli per vestiti e scarpe di marca, per macchine, ville, feste, viaggi, ma anche per la produzione delle loro canzoni. Viene anche descritto il modo di come vengono guadagnati. Quindi, in sintesi, quest’ album non rappresenta solo la vita di Metro Boomin ma lo stile di vita di tutti cantanti, di quello che hanno vissuto e di quello che stanno ancora vivendo, partiti dalla povertà e arrivando al successo con molti sacrifici superando tutte le difficoltà riscontrate nel percorso. TRACKLIST 1. On Time (con John Legend) 2. Superhero (con Future e Chris Brown) 3. Too Many Nights (con Future featuring Don Toliver) 4. Raindrops (con Travis Scott) 5. Umbrella (con Travis Scott e Young Nudy) 6. Trance (con Travis Scott e Young Thug) 7. Around Me (featuring Don Toliver) 8.Metro Spider (con Young Thug) 9.I Can’t Save You (interlude) (con Future featuring Don Toliver) 10. Creepin’ (con The Weeknd e 21Savage) 11. Niagara Falls (con Travis Scott e 21Savage) 12. Walk Em Down (con 21Savage featuring Mustafa) 13. Lock On Me (con Travis Scott e Future)\n\n14. Feel The Fiyaaaah (con A$ap Rocky featuring Takeoff) 15. All The Money (con Gunna) (Bonus track)"},
    {"title": "TREDICI PIETRO", "category": "Musica", "tag": "Recensione Album", "excerpt": "Il nuovo album di Tredici Pietro, un viaggio crudo e introspettivo.", "img": "tredici_pietro.jfif", "fullText": "Contenuto per TREDICI PIETRO non ancora disponibile integralmente."},
    {"title": "Aftersun - Il ricordo di un'estate", "category": "Cinema", "tag": "Recensione", "excerpt": "Un film delicato sul rapporto padre-figlia e la salute mentale.", "img": "aftersun_movie_poster_1773352108336.png", "fullText": "Aftersun Il film di oggi si intitola \"Aftersun\" di Charlotte Wells (regista, sceneggiatrice...) ed è uno dei miei film preferiti. Parla principalmente di salute mentale e del rapporto padre-figlia. Il film racconta di una vacanza in Grecia tra un giovane padre e sua figlia di dodici anni. Apparentemente questa può sembrare una semplice e tranquilla vacanza, ma quello che la ragazza non sa è che questo sarà l’ultimo momento che passerà con suo padre e gli ultimi ricordi che avrà di lui. \n\nDurante questo viaggio la ragazza avrà le sue prime esperienze; invece, suo padre si renderà conto di aver trasmesso a sua figlia la sua malattia mentale. Nel film viene menzionata molto spesso la nonna della ragazza, e si intuisce che i suoi genitori non sono più insieme. Nel corso della vacanza si può notare che viene girata una specie di documentario per volontà della bambina; infatti, si può vedere in alcuni frame la ragazza cresciuta che riguarda questi video, rivedendo i suoi ultimi momenti con suo padre. \n\nA parer mio, questo film aumenta la consapevolezza di come le malattie mentali possano essere trasmesse geneticamente e di come i bei momenti che passiamo con chi amiamo, anche senza rendercene conto, possano essere gli ultimi. Inizialmente può sembrare il solito film banale, noioso e con la solita storia, ma con il passare del tempo, durante il film, si capisce come non sia un film banale, anzi, ci si rende conto come questa storia abbia qualcosa di più rispetto alle altre, ovvero il rapporto che c’è dietro che, nonostante sia a volte contrastante, per la maggior parte del tempo fa notare l'affetto che c’è tra i due protagonisti. \n\nSi può notare anche come, nonostante uno dei due protagonisti principali sia una giovane ragazza dodicenne, la sua interpretazione sia eccezionale. Dunque, in conclusione, questo film è uno dei miei preferiti proprio perché tratta temi che molto spesso non vengono menzionati. Mi ha lasciato la consapevolezza di come il suicidio non sia la soluzione migliore, come spesso si crede, perché oltre ad uccidere noi stessi, uccidiamo anche chi ci ama di più. \n\nPer concludere, si può dire che questo film, una volta finito, lascia a tutti qualcosa di significativo e che anche i brevi momenti che passiamo con chi amiamo possono essere gli ultimi, e bisogna goderseli al massimo."},
    {"title": "Uncharted: Il Film", "category": "Cinema", "tag": "Recensione", "excerpt": "L'avventura di Nathan Drake arriva sul grande schermo.", "img": "uncharted_new.jfif", "fullText": "______________________ UNCHARTED: IL FILM Cercate un film di avventura e ladri, ispirato ad un gioco e che vi distolga dalla realtà per qualche ora? Allora Uncharted fa per voi. Diretto da Ruben Fleischer, con Tom Holland nei panni di Nathan Drake e Mark Wahlberg nei panni di Victor Sullivan, Uncharted. Un film dove i protagonisti non sono supereroi, poliziotti o studenti di un college americano, bensì ladri in cerca del tesoro di Ferdinando Magellano, e la sua ciurma “i famigerati 18”, e per trovarlo servono due chiavi a forma di croce. Una era del capitano e una della ciurma che è in possesso di Chloe una ladra furba di cui non fidarsi, l'altra è all'asta e toccherà a Nathan drake e Victor Sullivan rubarla, ma a mettergli i bastoni fra le ruote ci sarà il casato dei Moncada, di cui fa parte Santiago Moncada interpretato da Antonio Banderas, che pensano che la croce sia loro di diritto. Ora torniamo ai nostri protagonisti, Nathan Drake un ragazzo appassionato di storia come il fratello, che è scappato quando erano più piccoli, e Victor Sullivan un ladro di cui non ci si può fidare, abbandonò il fratello di Nathan (che si crede morto fino alla scena post-credit). però sullivan alla fine del film si redime sacrificando l’oro per salvare Nathan, questo ci insegna che non importa quanti sbagli facciamo avremo sempre la possibilità di redimerci e dimostrare di essere migliori, facendolo verremo ricompensati non con soldi o qualcosa di materiale ma con amore, gentilezza, amici e molto altro… Migliorando la nostra vita quotidiana e l'anima. Vi consiglio vivamente di guardare anche voi Uncharted e magari potrete capire meglio cosa può insegnare o potreste trovare un insegnamento diverso, oltre ovviamente a distrarsi un po’ con amici, parenti o da soli, questo sta a voi."},
    {"title": "Intervista: Prof.ssa Ferraro", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Quattro chiacchiere con Rossella Ferraro sulla passione per l'informatica.", "img": "chip_informatica.jpg", "fullText": "INTERVISTA PROF FERRARO\n“Ok, allora buongiorno. Siamo qui con…”\n“Rossella Ferraro, la prof di informatica.”\n“Salve prof, oggi verrà sottoposta a quattro domande tra cui l’ultima è facoltativa, può scegliere se rispondere oppure no.”\n“Va bene”\n“Allora, la prima domanda è: perché ha scelto di insegnare informatica?”\n“Perchè rispecchia un po ' i miei interessi, che avevo sin dalle scuole superiori, e quindi ho portato avanti questa mia passione per poi trasformarla nel mio lavoro.”\n“Qual’è il metodo migliore per insegnare informatica agli studenti?”\n“  È far parte del loro mondo, capire qual’è il loro linguaggio, il loro punto di vista e cercare di confrontarsi per arrivare a loro, in tutti i modi possibili”\n“Secondo lei, quale linguaggio di programmazione è più utile imparare per iniziare?”\n“Non è un vero e proprio linguaggio di programmazione, è un linguaggio che consente di imparare quali sono i processi per arrivare alla programmazione.”\n“Ok. L'ultima domanda è: cosa consiglia agli studenti che trovano difficile la programmazione?”\n“Allora, innanzitutto quella di chiedere al prof di classe, perchè a volte anche le domande fatte da più alunni diversi fa comprendere al professore quale argomento non è chiaro, non solo allo studente ma alla classe. E poi anche confrontarsi con i compagni che può rendere più semplice la comprensione grazie al rapporto in comune, che è differente con quello del professore.”\n“Va bene prof, grazie mille”\n“Figuratevi, è stato un piacere”"},
    {"title": "Intervista: Prof. Russo", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Il ruolo di docente e vicepreside tra responsabilità e sfide.", "img": "ufficio_vicepreside.jpg", "fullText": "INTERVISTA AL PROF RUSSO “è mezzogiorno quindi buon pomeriggio, siamo con il prof “ “Luigi Russo, nonché vicepreside della scuola da cinque anni” “Allora caro prof, lei oggi verrà sottoposto a quattro domande” “difficili?” “No, non si preoccupi” “Speriamo” “Allora, la prima domanda è: com'è conciliare il ruolo di docente con quello di vicepreside?” “Non sempre semplice, però penso di riuscirci abbastanza bene” \"assolutamente sì prof” “La seconda domanda è: qual’è la responsabilità più grande che sente nel suo ruolo?” “Allora, secondo me la gestione dei rapporti interpersonali, che secondo me sono importantissimi, quindi saper gestire a stare dalla parte dei ragazzi, docenti e soprattutto della preside, che non sempre è semplice.” \n\n“Dal suo punto di vista, quali sono le principali sfide della scuola oggi?” “Sfida fondamentale è che ogni alunno deve avere la possibilità di credere nelle proprie potenzialità, e non avvilirsi, perchè i problemi si affrontano un passo alla volta.” \n\n“Verissimo. Bene, siamo giunti all’ultima domanda, a cui può decidere liberamente se rispondere o meno: c’è una decisione presa come vicepreside che ricorda con particolare emozione?” \n\n“A questa domanda posso dirvi solo si, ma non posso andare oltre per una questioni di privacy\" \n\n“Va benissimo prof, la ringraziamo e a presto” “grazie a voi ragazze”"},
    {"title": "Intervista: Prof. Farina", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Matematica, fisica e il futuro dell'Intelligenza Artificiale.", "img": "matematica_fisica.jpg", "fullText": "INTERVISTA PROF FARINA “Allora, buongiorno, siamo qui con il prof?” “Raffaele Farina.” “E insegna?” “Matematica e fisica.” “Ok, perfetto. Oggi verrà sottoposto a quattro domande, tra cui l’ultima che è facoltativa a cui può scegliere se rispondere oppure no. Passiamo alla prima domanda. \n\nLa matematica è spesso temuta dagli studenti. Secondo lei, da cosa nasce questa difficoltà?” \n\n“Allora, secondo me questa difficoltà degli studenti verso la matematica è dovuta al fatto che, fondamentalmente, per studiare questo tipo di materia bisogna avere già una certa passione di base. Inoltre, c’è bisogno di una grande quantità di tempo per assimilare bene i concetti. Questa è la prima risposta che mi viene.” \n\n“Io parlo da studentessa: secondo me contano anche molti esercizi, perché poi la pratica rende migliori.” \n\n“Sì, sì, esattamente. C’è bisogno di tanta esercitazione e bisogna avere anche una passione, un amore di base verso questa materia per poi rendere al massimo.” \n\n“Allora, perfetto, passiamo alla seconda domanda. Qual è la soddisfazione più grande nel vedere un alunno progredire nella sua materia?” \n\n“Allora, sicuramente il nostro mestiere è quello di insegnare e trasferire le nostre conoscenze a voi studenti.” \n\n“Sì, assolutamente.” “È ovvio che nel momento in cui ci sono buoni risultati da parte degli studenti, il loro successo formativo diventa anche il nostro successo, perché vuol dire che abbiamo lavorato bene. Soprattutto in materie come matematica e fisica, dove è un po’ più difficile trasferire le nostre nozioni. Se uno o più ragazzi riescono bene in queste materie, siamo contenti anche di noi stessi perché vuol dire che abbiamo messo del nostro. \n\nSicuramente noi docenti di matematica ci impegniamo tantissimo, perché non tutti imparano nella stessa maniera. Quindi lo stesso concetto deve essere rappresentato in modalità diverse, perché ogni studente ha un modo differente di apprendere. Per esempio, uno studente non impara come ho imparato io, e quindi devo fornire più strumenti, devo utilizzare più strumenti per spiegare la stessa cosa in modalità diverse, affinché poi tutti capiscano quell’argomento.” \n\n“Ok, passiamo alla terza domanda. Quanto conta la logica nella formazione di uno studente anche al di fuori della matematica?” \n\n“Certo, la logica è alla base. Quando si esce dal liceo e si entra all’università, molte facoltà, per esempio medicina, prevedono test di ingresso in cui la logica è fondamentale. Ma anche per qualunque tipo di concorso: i primi test, quelli che selezionano molti candidati, sono proprio test di logica. \n\nE molta della logica, fondamentalmente, si impara attraverso la matematica e la fisica. Il primo strumento per risolvere gli esercizi di matematica è proprio la logica, soprattutto in quelli di geometria. Anche negli esami di Stato delle quinte, quando si affrontano argomenti come statistica e probabilità. \n\nQuindi già al liceo, attraverso matematica e fisica, diamo degli strumenti e facciamo i primi esercizi di logica, ovviamente penso che anche voi ve ne accorgiate: rispetto ad altre materie è molto diversa, e quindi è fondamentale.”\n\n“Siamo arrivati alla quarta e ultima domanda. Può scegliere se rispondere oppure no. C’è stato un momento della sua carriera in cui si è sentito particolarmente orgoglioso del suo lavoro?” \n\n“Sì. Soprattutto in questo periodo, perché con l’avvento dell’intelligenza artificiale e delle reti neurali la figura del matematico sta diventando molto importante. Infatti, la questione delle reti neurali e dell’intelligenza artificiale riguarda proprio problemi matematici. \n\nFondamentalmente le reti neurali devono essere addestrate e pre-addestrate. Addestrare queste intelligenze artificiali, come ChatGPT, significa risolvere un problema matematico che si chiama problema di minimo, che affrontiamo anche nelle prime fasi con i ragazzi del quinto anno. \n\nQuindi, per la figura del matematico questo è un bel periodo. Inoltre, recentemente sono contento perché, quando nelle classi quinte devo fare degli esempi di quello che studiamo, mi riferisco spesso all’intelligenza artificiale, che è uno dei temi più importanti e attuali.” \n\n“Sì, diciamo che se usata bene, a parer mio, è utilissima.” “Sì, esattamente. Per voi studenti di oggi e lavoratori di domani c’è una grande scommessa: portare avanti le tecnologie utilizzando quelle di adesso, come l’intelligenza artificiale, faccio un esempio: se prima l’umanità faceva dei passi avanti ogni dieci anni, per voi il divario sarà molto minore, perché utilizzerete strumenti potentissimi, e gli sviluppi che potrete ottenere sono altissimi. Raggiungerete grandi traguardi anche perché, se avete una difficoltà, potete risolverla utilizzando queste tecnologie che sono molto potenti.” \n\n“Infatti, riprendo quello che lei stava dicendo: anche la medicina, l’informatica e la matematica in questi ultimi anni stanno facendo passi da gigante.” \n\n“Sì, stanno facendo passi da gigante proprio grazie all’utilizzo di queste tecnologie che, se usate bene, possono portarci molto avanti.” \n\n“Io la ringrazio e le auguro una buona giornata. Grazie per l’intervista.”"},
    {"title": "Intervista: Prof.ssa Fioretto", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "L'importanza dell'inglese e i nuovi metodi di insegnamento coinvolgenti.", "img": "dizionario_inglese.jpg", "fullText": "INTERVISTA PROF FIORETTO “Buongiorno, oggi siamo qui con la professoressa?” “ Fioretto Alice” “che insegna?” “inglese.” “Oggi le faremo quattro domande, tra cui una è facoltativa. Allora, quanto è importante oggi conoscere l'inglese per il futuro degli studenti?” \n\n“Ti devo dare una scaletta da uno a dieci o devo argomentare?” “Argomenti argomenti. “ “Allora, secondo me è fondamentale perché ormai il mondo globalizzato è un mondo costantemente in connessione, e la lingua che ci unisce tutti è la lingua inglese, che ci piaccia oppure no. Insomma quindi è fondamentale conoscere una lingua che accomuni il nostro mondo con quello degli altri. Secondo me non è necessario conoscerla al 100% a livello per esempio grammaticale strutturale, l'importante è riuscire nella comunicazione, questo non vuol dire che dobbiamo parlare con i gesti, però comunque, dobbiamo cercare di immergerci in quella situazione in quella lingua per poi far sì che la cosa più importante è che la comunicazione riesca.” \n\n“Grazie. Qual è il metodo che usa per rendere le lezioni più coinvolgenti? Questa è perfetta per lei.” \n\n“ Ok, allora sicuramente cercare di non focalizzarmi sulla lezione frontale, come era un tempo, quindi spiegando e assegnando esercizi, ma cercare appunto di coinvolgere i ragazzi nella spiegazione, fare delle domande che cercano comunque di far ragionare i ragazzi, sicuramente utilizzando le nuove tecnologie digitali, per esempio come possono essere la LIM oppure magari sfruttando qualche video,e soprattutto le canzoni che è un linguaggio comune. Poi che altro… sicuramente qualcosa che possa effettivamente interessare gli studenti come può essere un film, una serie TV oppure anche un libro, quindi incentivare una cultura che sia extra scolastica.” \n\n“Nota differenze tra l'apprendimento delle lingue oggi e in passato?” “Sì, sicuramente c'è differenza soprattutto appunto nella struttura della lezione, come abbiamo detto, prima era una lezione molto più frontale, dove anche magari la conversazione veniva a mancare e invece adesso comunque ci si cerca di integrare gli studenti nella lezione, nella spiegazione, e quindi cercare di spostare il focus dall'insegnante allo studente e invece prima appunto era il contrario.” \n\n“Quarta domanda…vuoi farla la tu Adele?” “Si. Allora, qual è l'argomento che comunque non preferisce o che le da più dispiacere diciamo spiegare.” \n\n“È una bella domanda, perché effettivamente credo che in generale la grammatica per quanto riguarda l’inglese, ovviamente un po' annoia sempre, nel senso che non non la trovo\n\nsempre tanto stimolante, quindi a me piacerebbe avere il tempo, perché poi purtroppo questo nella scuola italiana non c'è perché tre ore non sono abbastanza, di poter insegnare la grammatica. Però se devo pensare a un argomento… direi sicuramente i conditional, perché è un argomento che un po' mi mi annoia fare” \n\n“Che tra l’altro dovremmo fare tra poco” “ Infatti vi sto preparando proprio per quello.“ “grazie prof” “ grazie a voi”"},
    {"title": "Intervista: Prof. Liccardo", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Sviluppare lo spirito critico attraverso lo studio delle scienze naturali.", "img": "microscopio_scienze.jpg", "fullText": "INTERVISTA PROF LICCARDO “Buongiorno. Siamo qui con il prof?” “Liccardo” “Che insegna?” “Scienze naturali” “Ok prof. Oggi lei verrà sottoposto a quattro domande tra cui l’ultima è facoltativa, può scegliere se rispondere oppure no. Quanto è importante sviluppare curiosità e spirito critico nello studio delle scienze?” \n\n“ É Importante, perché se non si riesce a cercare di far sì che i ragazzi possano essere interessati alla materia con curiosità, proprio le scienze naturali diventano una materia come tante altre che sono poco sperimentali” \n\n“ Ritiene che oggi gli studenti siano più o meno interessati ai temi scientifici rispetto al passato?” \n\n“ Penso più interessati, perché si sono resi conto che quello che ci circonda non è altro che le scienze, quindi quello che si insegna la scuola è la realtà che loro vedono intorno” \n\n“ Perfetto. Qual è l’argomento che suscita sempre maggior interesse tra le sue classi?” “ Beh dipende dalle classi, se parliamo di una seconda quando si inizia a parlare della cellula c’è molto interesse, in prima invece quando si parla dell’universo, alcune cose che possono sembrare scontate non lo sono e quindi c’è molta curiosità” \n\n“Ecco l’ultima domanda. C’è stata una scoperta scientifica che l’ha particolarmente affascinata nella sua vita?” \n\n“Come scoperta scientifica, si sicuramente è stata aldilà della…parliamo di scoperta scientifica quindi qualcosa che già c’era… la scoperta del DNA che ha fatto sì che si potessero in qualche modo manipolare e quindi poter arrivare a ridurre quello che poi sono le anomalie genetiche.” \n\n“Va bene prof, arrivederci e grazie”"},
    {"title": "Intervista: Prof.ssa Parigiano", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "L'amore per le Lettere e l'incontro con i grandi classici.", "img": "penna_lettere.jpg", "fullText": "INTERVISTA PROF PARIGIANO “Buongiorno, siamo con…” “La professoressa Parigiano” “Oggi prof verrà sottoposta a quattro domande, tra cui l’ultima può decidere se rispondere oppure no.” \n\n“Va bene” “Allora, la prima domanda è: cosa le piace di più del suo lavoro?” “Sicuramente il contatto con i ragazzi, la severità che devo mantenere, le informazioni che devo dare e cercare di trasmettere l’amore per questa materia fondamentale.” \n\n“Bellissima risposta. La seconda domanda è: qual’è la parte più difficile dell’insegnamento?” “Di non oltrepassare il limite, perchè alcuni ragazzi sconfinano, e noi dobbiamo sempre restare in media. Spesso non basta neanche contare fino a 10, ma dobbiamo sempre mantenere la calma che contraddistingue, perchè noi siamo da esempio, anche se non è proprio semplice.” \n\n“La terza domanda è: qual’è l’errore più comune che fanno gli studenti quando scrivono?” “Assolutamente errori di grammatica, come ad esempio la l senza ‘ oppure e senza accento.” \n\n“Bene, siamo arrivati all’ultima domanda” “Quanti anni ho?” “No no prof. Se potesse incontrare uno scrittore del passato, chi sceglierebbe e perchè?” “Domanda difficile, ma ultimamente mi piace molto Pirandello, perchè secondo me è colui che descrive al meglio il nostro divenire, le nostre maschere e il nostro modo di essere. Certo sono molto legata anche a Leopardi e Pascoli, ma il mondo pirandelliano è il mondo che mi sta facendo capire che noi siamo sempre un divenire,e non siamo statici.” \n\n“Va benissimo prof, grazie mille” “Figuratevi, alla prossima”"},
];

const articlesDatabase = articlesDatabaseRaw.map((a, i) => ({ 
    ...a, 
    id: `art-${i}`,
    link: `articolo.html?id=art-${i}`
}));

document.addEventListener('DOMContentLoaded', () => {
    const sidebar = document.getElementById('sidebar');
    const toggleBtn = document.getElementById('toggleBtn');
    const searchBtnIcon = document.getElementById('searchBtnIcon');
    const searchInput = document.getElementById('searchInput');
    const searchSubmit = document.getElementById('searchSubmit');

    // Function to toggle the sidebar
    const toggleSidebar = () => {
        if (!sidebar) return;
        const isExpanded = sidebar.classList.toggle('expanded');
        if (toggleBtn) toggleBtn.setAttribute('aria-expanded', isExpanded);
        if (isExpanded && searchInput) {
            setTimeout(() => { searchInput.focus(); }, 400);
        } else if (searchInput) {
            searchInput.blur();
        }
    };

    if (toggleBtn) toggleBtn.addEventListener('click', toggleSidebar);
    if (searchBtnIcon) searchBtnIcon.addEventListener('click', toggleSidebar);

    // ==========================================
    // LOGICA PAGINA CATEGORIA
    // ==========================================
    const categoryContainer = document.getElementById('categoryArticlesContainer');
    if (categoryContainer) {
        let currentCategory = "";
        const pathname = window.location.pathname.toLowerCase();
        if (pathname.includes('cinema.html')) currentCategory = 'Cinema';
        else if (pathname.includes('sport.html')) currentCategory = 'Sport';
        else if (pathname.includes('musica.html')) currentCategory = 'Musica';
        else if (pathname.includes('videogiochi.html')) currentCategory = 'Videogiochi';
        else if (pathname.includes('attualita-segre.html')) currentCategory = 'Attualità Segrè';

        if (currentCategory) {
            const categoryArticles = articlesDatabase.filter(a => a.category === currentCategory);
            if (categoryArticles.length > 0) {
                let htmlContent = '';
                categoryArticles.forEach((article, index) => {
                    htmlContent += `
                        <a href="${article.link}" class="article-card" style="animation-delay: ${index * 0.1}s">
                            <div class="article-image" style="background-image: url('${article.img}');"></div>
                            <div class="article-content">
                                <span class="article-tag">${article.tag}</span>
                                <span class="article-tag" style="background:#0F3859; margin-left:5px;">${article.category}</span>
                                <h2 class="article-title">${article.title}</h2>
                                <p class="article-excerpt">${article.excerpt}</p>
                            </div>
                        </a>
                    `;
                });
                categoryContainer.innerHTML = htmlContent;
            } else {
                categoryContainer.innerHTML = `<div style="grid-column: 1 / -1; text-align: center; padding: 50px;"><h2 style="color: var(--accent-red); margin-bottom: 20px;">Nessun articolo per questa categoria.</h2></div>`;
            }
        }
    }

    // ==========================================
    // LOGICA PAGINA RISULTATI RICERCA
    // ==========================================
    const searchResultsContainer = document.getElementById('searchResultsContainer');
    if (searchResultsContainer) {
        const urlParams = new URLSearchParams(window.location.search);
        const query = urlParams.get('q')?.toLowerCase() || "";
        const headerTitle = document.getElementById('searchHeaderTitle');
        
        if (query) {
            if (headerTitle) headerTitle.textContent = `Risultati per: "${query}"`;
            
            const results = articlesDatabase.filter(article => 
                article.title.toLowerCase().includes(query) ||
                article.excerpt.toLowerCase().includes(query) ||
                article.category.toLowerCase().includes(query) ||
                (article.fullText && article.fullText.toLowerCase().includes(query))
            );

            if (results.length > 0) {
                let htmlContent = '';
                results.forEach((article, index) => {
                    htmlContent += `
                        <a href="${article.link}" class="article-card" style="animation-delay: ${index * 0.1}s">
                            <div class="article-image" style="background-image: url('${article.img}');"></div>
                            <div class="article-content">
                                <span class="article-tag">${article.tag}</span>
                                <span class="article-tag" style="background:#0F3859; margin-left:5px;">${article.category}</span>
                                <h2 class="article-title">${article.title}</h2>
                                <p class="article-excerpt">${article.excerpt}</p>
                            </div>
                        </a>
                    `;
                });
                searchResultsContainer.innerHTML = htmlContent;
            } else {
                searchResultsContainer.innerHTML = `<div style="grid-column: 1 / -1; text-align: center; padding: 50px;"><h2 style="color: var(--text-blue); opacity: 0.5;">Nessun risultato trovato per "${query}".</h2></div>`;
            }
        }
    }

    const performSearch = () => {
        if (!searchInput) return;
        const query = searchInput.value.trim();
        if (query) window.location.href = `risultati.html?q=${encodeURIComponent(query)}`;
    };

    if (searchSubmit) searchSubmit.addEventListener('click', performSearch);
    if (searchInput) {
        searchInput.addEventListener('keypress', (e) => { if(e.key === 'Enter') performSearch(); });
    }

    // ==========================================
    // LOGICA VISUALIZZAZIONI
    // ==========================================
    const COOLDOWN_MS = 10 * 60 * 1000; 
    const API_NAMESPACE = 'ilpostino_official_v1_live_v2';

    const incrementViewWithCooldownAsync = async (counterName, timestampKey) => {
        let lastVisitTime = parseInt(localStorage.getItem(timestampKey)) || 0;
        const now = Date.now();
        try {
            if (now - lastVisitTime > COOLDOWN_MS) {
                const res = await fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${counterName}/up`);
                const data = await res.json();
                localStorage.setItem(timestampKey, now);
                return data.count;
            } else {
                const res = await fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${counterName}/`);
                if (res.ok) {
                    const data = await res.json();
                    return data.count;
                } else return 0;
            }
        } catch (e) {
            let localViews = parseInt(localStorage.getItem(counterName)) || 0;
            if (now - lastVisitTime > COOLDOWN_MS) {
                localViews++;
                localStorage.setItem(counterName, localViews);
                localStorage.setItem(timestampKey, now);
            }
            return localViews;
        }
    };

    const mainContent = document.querySelector('.main-content');
    if (mainContent && !document.querySelector('.global-view-counter')) {
        const viewCounterDiv = document.createElement('div');
        viewCounterDiv.className = 'global-view-counter';
        viewCounterDiv.innerHTML = `<span class="metric-icon">👁️</span><span class="metric-value" id="viewCount">...</span>`;
        mainContent.parentNode.insertBefore(viewCounterDiv, mainContent);
    }

    const viewCountEl = document.getElementById('viewCount');
    if (viewCountEl) {
        incrementViewWithCooldownAsync('site_views_real', 'last_visit_global_time').then(v => { viewCountEl.textContent = v.toLocaleString('it-IT'); });
    }

    // ==========================================
    // LOGICA PAGINA SINGOLO ARTICOLO
    // ==========================================
    const articleReader = document.getElementById('articleReader');
    const articleError = document.getElementById('articleError');
    if (articleReader) {
        const urlParams = new URLSearchParams(window.location.search);
        const articleId = urlParams.get('id');
        const article = articlesDatabase.find(a => a.id === articleId);

        if (article) {
            articleReader.style.display = 'block';
            if (articleError) articleError.style.display = 'none';
            document.title = `${article.title} - Il Postino`;
            document.getElementById('articleTitle').textContent = article.title;
            document.getElementById('articleTag').textContent = article.tag;
            document.getElementById('articleCategory').textContent = article.category;
            document.getElementById('articleImg').src = article.img;
            
            const body = document.getElementById('articleBody');
            if (article.fullText) {
                body.innerHTML = article.fullText.split('\n').filter(l => l.trim()).map(p => `<p>${p}</p>`).join('');
            }

            const articleViewEl = document.getElementById('articleViewCount');
            if (articleViewEl) {
                incrementViewWithCooldownAsync(`views_real_${article.id}`, `last_visit_real_${article.id}`).then(v => { articleViewEl.textContent = v.toLocaleString('it-IT'); });
            }

            const likeBtn = document.getElementById('articleLikeBtn');
            const likeCountEl = document.getElementById('articleLikeCount');
            const storageKey = `likes_real_${article.id}`;
            const userLikedKey = `user_liked_real_${article.id}`;

            fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${storageKey}/`)
                .then(res => res.ok ? res.json() : {count: 0})
                .then(data => { likeCountEl.textContent = data.count.toLocaleString('it-IT'); });

            if(localStorage.getItem(userLikedKey) === 'true') {
                if (likeBtn) likeBtn.classList.add('liked');
                const heartIcon = likeBtn ? likeBtn.querySelector('.heart-icon') : null;
                if (heartIcon) heartIcon.textContent = '❤️';
            }

            if (likeBtn) {
                likeBtn.addEventListener('click', () => {
                    const heartIcon = likeBtn.querySelector('.heart-icon');
                    let currentlyLiked = localStorage.getItem(userLikedKey) === 'true';
                    if (currentlyLiked) {
                        localStorage.setItem(userLikedKey, 'false');
                        likeBtn.classList.remove('liked');
                        if (heartIcon) heartIcon.textContent = '🤍';
                        fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${storageKey}/down`).then(res => res.json()).then(d => { if(likeCountEl) likeCountEl.textContent = d.count.toLocaleString('it-IT'); });
                    } else {
                        localStorage.setItem(userLikedKey, 'true');
                        likeBtn.classList.add('liked');
                        if (heartIcon) heartIcon.textContent = '❤️';
                        fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${storageKey}/up`).then(res => res.json()).then(d => { if(likeCountEl) likeCountEl.textContent = d.count.toLocaleString('it-IT'); });
                    }
                });
            }
        } else {
            if (articleReader) articleReader.style.display = 'none';
            if (articleError) articleError.style.display = 'block';
        }
    }
});
